const ERR_NON_ADJ = "Cannot connect non-adjacent islands";
const ERR_MAX_PAIR = "Max 2 bridges per pair";
const ERR_EXCEED = "Island would exceed its number";
const ERR_CROSS = "Bridges would cross";

export function canonicalBridgeKey(from, to) {
  const a = { x: from.x, y: from.y };
  const b = { x: to.x, y: to.y };
  const first = a.x < b.x || (a.x === b.x && a.y <= b.y) ? a : b;
  const second = first === a ? b : a;
  return `${first.x},${first.y},${second.x},${second.y}`;
}

function isAligned(a, b) {
  return a.x === b.x || a.y === b.y;
}

export function areAdjacent(islands, from, to) {
  if (!from || !to) return false;
  if (from.id === to.id) return false;
  if (!isAligned(from, to)) return false;

  // Must be no island strictly between them on the segment.
  if (from.x === to.x) {
    const x = from.x;
    const y1 = Math.min(from.y, to.y);
    const y2 = Math.max(from.y, to.y);
    for (const isl of islands) {
      if (isl.id === from.id || isl.id === to.id) continue;
      if (isl.x === x && isl.y > y1 && isl.y < y2) return false;
    }
    return true;
  }

  const y = from.y;
  const x1 = Math.min(from.x, to.x);
  const x2 = Math.max(from.x, to.x);
  for (const isl of islands) {
    if (isl.id === from.id || isl.id === to.id) continue;
    if (isl.y === y && isl.x > x1 && isl.x < x2) return false;
  }
  return true;
}

function parseKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

function segmentCrosses(aKey, bKey) {
  const A = parseKey(aKey);
  const B = parseKey(bKey);

  const Avert = A.x1 === A.x2;
  const Bvert = B.x1 === B.x2;

  if (Avert === Bvert) return false; // parallel can't cross (collinear overlap can't happen with adjacency rules)

  const V = Avert ? A : B;
  const H = Avert ? B : A;

  const vx = V.x1;
  const vyMin = Math.min(V.y1, V.y2);
  const vyMax = Math.max(V.y1, V.y2);

  const hy = H.y1;
  const hxMin = Math.min(H.x1, H.x2);
  const hxMax = Math.max(H.x1, H.x2);

  const ix = vx;
  const iy = hy;

  // strict intersection interior to both segments
  const withinV = iy > vyMin && iy < vyMax;
  const withinH = ix > hxMin && ix < hxMax;
  if (!withinV || !withinH) return false;

  // Crossing at an island coordinate is allowed, but with adjacency segments,
  // interior intersection cannot be an endpoint. Still, keep guard:
  const isEndpoint =
    (ix === V.x1 && iy === V.y1) || (ix === V.x2 && iy === V.y2) ||
    (ix === H.x1 && iy === H.y1) || (ix === H.x2 && iy === H.y2);
  if (isEndpoint) return false;

  return true;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }

  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: ERR_NON_ADJ };
  }

  const key = canonicalBridgeKey(from, to);
  const current = bridges.get(key) ?? 0;
  const next = current + delta;

  if (next < 0) return { valid: true, error: null }; // removal always ok
  if (next > 2) return { valid: false, error: ERR_MAX_PAIR };

  // check island max
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = (counts.get(from.id) ?? 0) + delta;
  const toCount = (counts.get(to.id) ?? 0) + delta;
  if (fromCount > from.value || toCount > to.value) {
    return { valid: false, error: ERR_EXCEED };
  }

  // check crossing (for additions only)
  if (delta > 0 && next > 0) {
    for (const [otherKey, otherN] of bridges.entries()) {
      if (!otherN) continue;
      if (otherKey === key) continue;
      if (segmentCrosses(key, otherKey)) {
        return { valid: false, error: ERR_CROSS };
      }
    }
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  const posToId = new Map(islands.map((i) => [`${i.x},${i.y}`, i.id]));
  const adj = new Map(islands.map((i) => [i.id, []]));

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = posToId.get(`${x1},${y1}`);
    const b = posToId.get(`${x2},${y2}`);
    if (a == null || b == null) continue;
    adj.get(a).push(b);
    adj.get(b).push(a);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const stack = [start];
  while (stack.length) {
    const cur = stack.pop();
    for (const nxt of adj.get(cur) ?? []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        stack.push(nxt);
      }
    }
  }

  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  // counts satisfied
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }

  // no crossings
  const keys = Array.from(bridges.entries()).filter(([, n]) => n > 0).map(([k]) => k);
  for (let i = 0; i < keys.length; i++) {
    for (let j = i + 1; j < keys.length; j++) {
      if (segmentCrosses(keys[i], keys[j])) return false;
    }
  }

  // connected
  return checkConnectivity(islands, bridges);
}

export const ERRORS = {
  ERR_NON_ADJ,
  ERR_MAX_PAIR,
  ERR_EXCEED,
  ERR_CROSS
};
