import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canonicalBridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function islandPixel(isl) {
  return { cx: isl.x * GRID, cy: isl.y * GRID };
}

function bridgeEndpointsPx(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return {
    x1: x1 * GRID,
    y1: y1 * GRID,
    x2: x2 * GRID,
    y2: y2 * GRID,
    gx1: x1,
    gy1: y1,
    gx2: x2,
    gy2: y2
  };
}

function findIslandById(islands, id) {
  return islands.find((i) => i.id === id) ?? null;
}

function findNextIslandInDirection(islands, from, dir) {
  // dir: 'left'|'right'|'up'|'down'
  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;
    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      if (!best || isl.x > best.x) best = isl;
    } else if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      if (!best || isl.x < best.x) best = isl;
    } else if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      if (!best || isl.y > best.y) best = isl;
    } else if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      if (!best || isl.y < best.y) best = isl;
    }
  }
  return best;
}

export default function App() {
  const [puzzleName, setPuzzleName] = useState('Easy');
  const puzzle = useMemo(
    () => puzzles.find((p) => p.name === puzzleName) ?? puzzles[0],
    [puzzleName]
  );

  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null); // mouse selection / keyboard selection
  const [cursorId, setCursorId] = useState(islands[0]?.id ?? 0);
  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  // Reset bridges and selection on puzzle change
  useEffect(() => {
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setCursorId(islands[0]?.id ?? 0);
  }, [puzzleName]); // eslint-disable-line react-hooks/exhaustive-deps

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function applyBridgeDelta(from, to, delta) {
    const verdict = canAddBridge(islands, bridges, from, to, delta);
    if (!verdict.valid) {
      setError(verdict.error);
      return false;
    }

    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) ?? 0;
    const next = Math.max(0, current + delta);

    const nextMap = new Map(bridges);
    if (next === 0) nextMap.delete(key);
    else nextMap.set(key, next);

    setBridges(nextMap);
    setError(null);
    return true;
  }

  function cycleBridge(from, to) {
    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) ?? 0;
    // none -> single -> double -> none
    const target = current === 0 ? 1 : current === 1 ? 2 : 0;
    const delta = target - current;
    if (delta === 0) return true;
    return applyBridgeDelta(from, to, delta);
  }

  function removeBridge(from, to) {
    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) ?? 0;
    if (current === 0) return false;

    const nextMap = new Map(bridges);
    nextMap.delete(key);
    setBridges(nextMap);
    setError(null);
    return true;
  }

  function handleIslandActivate(targetId, { removeOnly = false } = {}) {
    const target = findIslandById(islands, targetId);
    if (!target) return;

    // First click/enter selects
    if (selectedId == null) {
      setSelectedId(targetId);
      return;
    }

    // Second click on same island just keeps selection
    if (selectedId === targetId) return;

    const from = findIslandById(islands, selectedId);
    const to = target;
    if (!from || !to) {
      setSelectedId(null);
      return;
    }

    if (removeOnly) {
      removeBridge(from, to);
    } else {
      cycleBridge(from, to);
    }

    // after toggle/removal, selection clears (fresh pair next)
    setSelectedId(null);
  }

  function onIslandClick(e, islId) {
    e.preventDefault();
    setCursorId(islId);
    handleIslandActivate(islId, { removeOnly: false });
  }

  function onIslandContextMenu(e, islId) {
    e.preventDefault();
    setCursorId(islId);
    // if we already selected another island, remove bridge between them
    if (selectedId != null && selectedId !== islId) {
      handleIslandActivate(islId, { removeOnly: true });
      return;
    }
    // otherwise: no-op (spec only requires remove on existing bridge between A and B)
  }

  function onIslandCtrlClick(e, islId) {
    if (!e.ctrlKey && e.button !== 2) return;
    // ctrl+click should remove if second island exists
    e.preventDefault();
    setCursorId(islId);
    if (selectedId != null && selectedId !== islId) {
      handleIslandActivate(islId, { removeOnly: true });
    }
  }

  useEffect(() => {
    function onKeyDown(e) {
      const cur = findIslandById(islands, cursorId) ?? islands[0];
      if (!cur) return;

      if (e.key === 'Escape') {
        setSelectedId(null);
        return;
      }

      const dirMap = {
        ArrowLeft: 'left',
        ArrowRight: 'right',
        ArrowUp: 'up',
        ArrowDown: 'down'
      };

      if (e.key in dirMap) {
        e.preventDefault();
        const next = findNextIslandInDirection(islands, cur, dirMap[e.key]);
        if (next) setCursorId(next.id);
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        // keyboard activation uses cursor
        handleIslandActivate(cur.id, { removeOnly: false });
      }

      // Ctrl+Enter: remove bridge between selected and cursor
      if ((e.key === 'Enter' || e.key === 'Return') && e.ctrlKey) {
        e.preventDefault();
        if (selectedId != null && selectedId !== cur.id) {
          handleIslandActivate(cur.id, { removeOnly: true });
        }
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [cursorId, islands, selectedId]);

  const bridgeLines = useMemo(() => {
    const lines = [];
    for (const [key, n] of bridges.entries()) {
      if (n <= 0) continue;
      const { x1, y1, x2, y2 } = bridgeEndpointsPx(key);
      const horizontal = y1 === y2;

      const offset = 5;
      if (n === 1) {
        lines.push({ key: `${key}:1`, x1, y1, x2, y2 });
      } else if (n === 2) {
        if (horizontal) {
          lines.push({ key: `${key}:a`, x1, y1: y1 - offset, x2, y2: y2 - offset });
          lines.push({ key: `${key}:b`, x1, y1: y1 + offset, x2, y2: y2 + offset });
        } else {
          lines.push({ key: `${key}:a`, x1: x1 - offset, y1, x2: x2 - offset, y2 });
          lines.push({ key: `${key}:b`, x1: x1 + offset, y1, x2: x2 + offset, y2 });
        }
      }
    }
    return lines;
  }, [bridges]);

  const cursorIsland = findIslandById(islands, cursorId) ?? islands[0] ?? null;
  const cursorPx = cursorIsland ? islandPixel(cursorIsland) : { cx: 0, cy: 0 };

  return (
    <div className="app">
      <div className="hud">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleName}
            onChange={(e) => setPuzzleName(e.target.value)}
          >
            <option value="Easy">Easy</option>
            <option value="Medium">Medium</option>
            <option value="Hard">Hard</option>
          </select>
        </label>
        <button
          type="button"
          onClick={() => {
            setBridges(new Map());
            setSelectedId(null);
            setError(null);
          }}
        >
          Reset
        </button>
        <div className="status">
          {selectedId != null ? `Selected: ${selectedId}` : 'Selected: -'}
        </div>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        ref={svgRef}
        className="board"
        width={SVG_W}
        height={SVG_H}
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
      >
        {/* Bridges */}
        {bridgeLines.map((l) => (
          <line
            key={l.key}
            x1={l.x1}
            y1={l.y1}
            x2={l.x2}
            y2={l.y2}
            stroke="#0f0"
            strokeWidth="3"
            strokeLinecap="round"
          />
        ))}

        {/* Keyboard cursor (NOT a circle) */}
        {cursorIsland ? (
          <rect
            x={cursorPx.cx - 18}
            y={cursorPx.cy - 18}
            width={36}
            height={36}
            fill="none"
            stroke="#0f0"
            strokeWidth="2"
            strokeDasharray="4 3"
          />
        ) : null}

        {/* Islands */}
        {islands.map((isl) => {
          const { cx, cy } = islandPixel(isl);
          const isSelected = selectedId === isl.id;
          const current = counts.get(isl.id) ?? 0;

          return (
            <g
              key={isl.id}
              onClick={(e) => onIslandClick(e, isl.id)}
              onContextMenu={(e) => onIslandContextMenu(e, isl.id)}
              onMouseDown={(e) => onIslandCtrlClick(e, isl.id)}
              style={{ cursor: 'pointer' }}
            >
              <circle
                cx={cx}
                cy={cy}
                r={16}
                fill={isSelected ? '#062' : 'black'}
                stroke="#0f0"
                strokeWidth="2"
              />
              <text
                x={cx}
                y={cy + 5}
                textAnchor="middle"
                fontSize="16"
                fill="#0f0"
              >
                {isl.value}
              </text>
              {/* small current count indicator */}
              <text
                x={cx}
                y={cy + 28}
                textAnchor="middle"
                fontSize="10"
                fill="#0f0"
              >
                {current}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
