import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canonicalBridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function islandPixel(isl) {
  return { cx: isl.x * GRID, cy: isl.y * GRID };
}

function bridgeEndpointsPx(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return {
    x1: x1 * GRID,
    y1: y1 * GRID,
    x2: x2 * GRID,
    y2: y2 * GRID,
    gx1: x1,
    gy1: y1,
    gx2: x2,
    gy2: y2
  };
}

function findIslandById(islands, id) {
  return islands.find((i) => i.id === id) ?? null;
}

function findNextIslandInDirection(islands, from, dir) {
  // dir: 'left'|'right'|'up'|'down'
  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;
    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      if (!best || isl.x > best.x) best = isl;
    } else if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      if (!best || isl.x < best.x) best = isl;
    } else if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      if (!best || isl.y > best.y) best = isl;
    } else if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      if (!best || isl.y < best.y) best = isl;
    }
  }
  return best;
}

export default function App() {
  const [puzzleName, setPuzzleName] = useState('Easy');
  const puzzle = useMemo(
    () => puzzles.find((p) => p.name === puzzleName) ?? puzzles[0],
    [puzzleName]
  );

  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null); // mouse selection / keyboard selection
  const [cursorId, setCursorId] = useState(islands[0]?.id ?? 0);
  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  // Reset bridges and selection on puzzle change
  useEffect(() => {
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setCursorId(islands[0]?.id ?? 0);
  }, [puzzleName]); // eslint-disable-line react-hooks/exhaustive-deps

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function applyBridgeDelta(from, to, delta) {
    const verdict = canAddBridge(islands, bridges, from, to, delta);
    if (!verdict.valid) {
      setError(verdict.error);
      return false;
    }

    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) ?? 0;
    const next = Math.max(0, current + delta);

    const nextMap = new Map(bridges);
    if (next === 0) nextMap.delete(key);
    else nextMap.set(key, next);

    setBridges(nextMap);
    setError(null);
    return true;
  }

  function cycleBridge(from, to) {
    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) ?? 0;
    // none -> single -> double -> none
    const target = current === 0 ? 1 : current === 1 ? 2 : 0;
    const delta = target - current;
    if (delta === 0) return true;
    return applyBridgeDelta(from, to, delta);
  }

  function removeBridge(from, to) {
    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) ?? 0;
    if (current === 0) return false;

    const nextMap = new Map(bridges);
    nextMap.delete(key);
    setBridges(nextMap);
    setError(null);
    return true;
  }

  function handleIslandActivate(targetId, { removeOnly = false } = {}) {
    const target = findIslandById(islands, targetId);
    if (!target) return;

    // First click/enter selects
    if (selectedId == null) {
      setSelectedId(targetId);
      return;
    }

    // Second click on same island just keeps selection
    if (selectedId === targetId) return;

    const from = findIslandById(islands, selectedId);
    const to = target;
    if (!from || !to) {
      setSelectedId(null);
      return;
    }

    if (removeOnly) {
      removeBridge(from, to);
    } else {
      cycleBridge(from, to);
    }

    // after toggle/removal, selection clears (fresh pair next)
    setSelectedId(null);
  }

