    setCursorId(islId);
    handleIslandActivate(islId, { removeOnly: false });
  }

  function onIslandContextMenu(e, islId) {
    e.preventDefault();
    setCursorId(islId);
    // if we already selected another island, remove bridge between them
    if (selectedId != null && selectedId !== islId) {
      handleIslandActivate(islId, { removeOnly: true });
      return;
    }
    // otherwise: no-op (spec only requires remove on existing bridge between A and B)
  }

  function onIslandCtrlClick(e, islId) {
    if (!e.ctrlKey && e.button !== 2) return;
