    function onKeyDown(e) {
      const cur = findIslandById(islands, cursorId) ?? islands[0];
      if (!cur) return;

      if (e.key === 'Escape') {
        setSelectedId(null);
        return;
      }

      const dirMap = {
        ArrowLeft: 'left',
        ArrowRight: 'right',
        ArrowUp: 'up',
        ArrowDown: 'down'
      };

      if (e.key in dirMap) {
        e.preventDefault();
        const next = findNextIslandInDirection(islands, cur, dirMap[e.key]);
        if (next) setCursorId(next.id);
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        // keyboard activation uses cursor
        handleIslandActivate(cur.id, { removeOnly: false });
      }

      // Ctrl+Enter: remove bridge between selected and cursor
      if ((e.key === 'Enter' || e.key === 'Return') && e.ctrlKey) {
        e.preventDefault();
        if (selectedId != null && selectedId !== cur.id) {
          handleIslandActivate(cur.id, { removeOnly: true });
        }
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [cursorId, islands, selectedId]);

  const bridgeLines = useMemo(() => {
    const lines = [];
    for (const [key, n] of bridges.entries()) {
      if (n <= 0) continue;
      const { x1, y1, x2, y2 } = bridgeEndpointsPx(key);
      const horizontal = y1 === y2;

      const offset = 5;
      if (n === 1) {
        lines.push({ key: `${key}:1`, x1, y1, x2, y2 });
      } else if (n === 2) {
        if (horizontal) {
          lines.push({ key: `${key}:a`, x1, y1: y1 - offset, x2, y2: y2 - offset });
          lines.push({ key: `${key}:b`, x1, y1: y1 + offset, x2, y2: y2 + offset });
        } else {
          lines.push({ key: `${key}:a`, x1: x1 - offset, y1, x2: x2 - offset, y2 });
          lines.push({ key: `${key}:b`, x1: x1 + offset, y1, x2: x2 + offset, y2 });
        }
      }
    }
    return lines;
  }, [bridges]);

  const cursorIsland = findIslandById(islands, cursorId) ?? islands[0] ?? null;
  const cursorPx = cursorIsland ? islandPixel(cursorIsland) : { cx: 0, cy: 0 };

  return (
    <div className="app">
      <div className="hud">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleName}
            onChange={(e) => setPuzzleName(e.target.value)}
          >
            <option value="Easy">Easy</option>
            <option value="Medium">Medium</option>
            <option value="Hard">Hard</option>
          </select>
        </label>
        <button
          type="button"
          onClick={() => {
            setBridges(new Map());
            setSelectedId(null);
            setError(null);
          }}
        >
          Reset
        </button>
        <div className="status">
          {selectedId != null ? `Selected: ${selectedId}` : 'Selected: -'}
        </div>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        ref={svgRef}
        className="board"
        width={SVG_W}
        height={SVG_H}
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
      >
        {/* Bridges */}
        {bridgeLines.map((l) => (
          <line
            key={l.key}
            x1={l.x1}
            y1={l.y1}
            x2={l.x2}
            y2={l.y2}
            stroke="#0f0"
            strokeWidth="3"
            strokeLinecap="round"
          />
        ))}

        {/* Keyboard cursor (NOT a circle) */}
        {cursorIsland ? (
          <rect
            x={cursorPx.cx - 18}
            y={cursorPx.cy - 18}
            width={36}
            height={36}
            fill="none"
            stroke="#0f0"
            strokeWidth="2"
            strokeDasharray="4 3"
          />
        ) : null}

        {/* Islands */}
        {islands.map((isl) => {
          const { cx, cy } = islandPixel(isl);
          const isSelected = selectedId === isl.id;
          const current = counts.get(isl.id) ?? 0;

          return (
            <g
              key={isl.id}
              onClick={(e) => onIslandClick(e, isl.id)}
              onContextMenu={(e) => onIslandContextMenu(e, isl.id)}
              onMouseDown={(e) => onIslandCtrlClick(e, isl.id)}
              style={{ cursor: 'pointer' }}
            >
              <circle
                cx={cx}
                cy={cy}
                r={16}
                fill={isSelected ? '#062' : 'black'}
                stroke="#0f0"
                strokeWidth="2"
              />
              <text
                x={cx}
                y={cy + 5}
                textAnchor="middle"
                fontSize="16"
                fill="#0f0"
              >
                {isl.value}
              </text>
              {/* small current count indicator */}
              <text
                x={cx}
                y={cy + 28}
                textAnchor="middle"
                fontSize="10"
                fill="#0f0"
              >
                {current}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
